-- 创建军团
function LxGuildHandler:CreateGuildReq(param)
    local proto     = LxProtoHelper.CreateProto(LxProtoIds.CreateGuildReq)
    proto.name      = param.name
    proto.notice    = param.notice
    proto.needPower = param.needPower
    proto.needLevel = param.needLevel
    proto.autoAgree = param.autoAgree
    for _, v in ipairs(param.emblems) do
        table.insert(proto.emblems, v)
    end
    SendMessage(LxProtoIds.CreateGuildReq, proto)
end

-- 修改军团设置,支持单字段修改
function LxGuildHandler:UpdateGuildSetupReq(param)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.UpdateGuildSetupReq)
    if param.newName ~= nil then
        proto.newName = param.newName
    end
    if param.notice ~= nil then
        proto.notice = param.notice
    end
    if param.needPower ~= nil then
        proto.needPower = param.needPower
    end
    if param.needLevel ~= nil then
        proto.needLevel = param.needLevel
    end
    if param.autoAgree ~= nil then
        proto.autoAgree = param.autoAgree
    end
    for _, v in ipairs(param.emblems or {}) do
        table.insert(proto.emblems, v)
    end

    for _, v in ipairs(param.permissions or {}) do
        local obj = LxProtoHelper.CreateProto(LxProtoIds.GuildPermissionObj)
        obj.guildRank = v.guildRank
        for _, permissionId in ipairs(v.permission) do
            table.insert(obj.permission, permissionId)
        end
        table.insert(proto.permissions, obj)
    end

    for _, v in ipairs(param.conditions or {}) do
        local obj = LxProtoHelper.CreateProto(LxProtoIds.GuildUpConditionObj)
        obj.guildRank = v.guildRank
        obj.nickname = v.nickname
        local items = obj.conditions
        for i,value in ipairs(v.conditions) do
            local kv = items:add()
            kv.key = value.key
            kv.value = value.value
        end
        obj.autoRank = v.autoRank
        table.insert(proto.conditions, obj)
    end

    if param.openRank ~= nil then
        proto.openRank = param.openRank
    end

    SendMessage(LxProtoIds.UpdateGuildSetupReq, proto)
end

