-- 军团模块关联数据,登录推送
function LxGuildHandler:OnGuildGlobalFieldResp(pb)
    local oldJobId = ModuleCenter.Guild:GetMyJobId()
    WorldCenter.Guild:UpdateGuildData(pb.globalObj.guildObj)
    ModuleCenter.Guild:SetGuildInfo(pb.globalObj.guildObj)
    ModuleCenter.Guild:SetGuildRecruitInfo(pb.globalObj.recruitInfo)
    ModuleCenter.Guild:SetGuildDonateInfo(pb.globalObj.donateInfo)
    ModuleCenter.Guild:SetCanJoinGuildEndTime(pb.globalObj.punishTime)
    ModuleCenter.Guild:SetNeverJoinGuildState(pb.globalObj.neverJoin)
    ModuleCenter.Guild:SetGuildPermissions(pb.globalObj.permissions)
    ModuleCenter.Guild:SetGuildRankConditions(pb.globalObj.conditions)
    ModuleCenter.Guild:SetGuildOpenRankState(pb.globalObj.openRank)

    local newJobId = ModuleCenter.Guild:GetMyJobId()

    if newJobId ~= GuildJob.Member and oldJobId == GuildJob.Member then
        self:ViewApplyListReq()
        self:NoticeHistoryReq()
    end
    CtrlCenter.City:RefreshBuildGuildHelp()
    FireEvent(EventNames.GUILD_INFO_CHANGE)
    FireEvent(EventNames.GUILD_HELPRED)
    if not CtrlCenter.Guild:HadGuild() then
        if IsOpenPanel(UiNames.GuildHome) then
            MgrCenter.PanelMgr:CloseAllOrdinaryView()
        end 
    end
    if CtrlCenter.Guild:HadGuild() then
        if IsOpenPanel(UiNames.GuildApplyList) then
            if not IsOpenPanel(UiNames.GuildHome) then
                ClosePanel(UiNames.GuildApplyList)
                ClosePanel(UiNames.GuildFirstCreate)
                local guildInfo = ModuleCenter.Guild:GetGuildInfo()
                if guildInfo then
                    ShowSysMsg(string.replace(I18nText(5586),guildInfo.name))
                end
                CtrlCenter.Guild:OpenGuild()
                FireEvent(EventNames.GUILD_JOIN)
            end
        end 
    end
end

-- 军团模块关联数据,一次下发字段不固定
function LxGuildHandler:OnGuildGlobalObj(pb)
    if pb:HasField("guildObj") then
        local oldJobId = ModuleCenter.Guild:GetMyJobId()

        ModuleCenter.Guild:SetGuildInfo(pb.guildObj)

        local newJobId = ModuleCenter.Guild:GetMyJobId()
        if newJobId ~= GuildJob.Member and oldJobId == GuildJob.Member then
            self:ViewApplyListReq()
        end
    end
    if pb:HasField("donateInfo") then
        ModuleCenter.Guild:SetGuildDonateInfo(pb.donateInfo)
    end
    if pb:HasField("recruitInfo") then
        ModuleCenter.Guild:SetGuildRecruitInfo(pb.recruitInfo)
    end
    if pb:HasField("punishTime") then
        ModuleCenter.Guild:SetCanJoinGuildEndTime(pb.punishTime)
    end
    if pb:HasField("neverJoin") then
        ModuleCenter.Guild:SetNeverJoinGuildState(pb.neverJoin)
    end
    if pb:HasField("permissions") then
        ModuleCenter.Guild:SetGuildPermissions(pb.permissions)
    end

    if pb:HasField("conditions") then
        ModuleCenter.Guild:SetGuildRankConditions(pb.conditions)
    end

    if pb:HasField("openRank") then
        ModuleCenter.Guild:SetGuildOpenRankState(pb.openRank)
    end

    FireEvent(EventNames.GUILD_INFO_CHANGE)
end

