-- 申请加入
function LxGuildHandler:OnApplyJoinGuildResp(pb)
    if pb.state == 2 then
        -- 1申请成功，2直接加入军团
        if not IsOpenPanel(UiNames.GuildHome) then
            ClosePanel(UiNames.GuildApplyList)
            ClosePanel(UiNames.GuildFirstCreate)
            local guildInfo = ModuleCenter.Guild:GetGuildInfo()
            if guildInfo then
                ShowSysMsg(string.replace(I18nText(5586),guildInfo.name))
            end
            CtrlCenter.Guild:OpenGuild()
            FireEvent(EventNames.GUILD_JOIN)
        end
        return
    end
    ModuleCenter.Guild:SetGuildApplyState(pb.guildId, true)
    FireEvent(EventNames.GUILD_LIST_CHANGE)
end

-- 一键申请加入
function LxGuildHandler:OnFastApplyJoinGuildResp(pb)
    if pb.state == 2 then
        -- 1申请成功，2直接加入军团
        if not IsOpenPanel(UiNames.GuildHome) then
            ClosePanel(UiNames.GuildApplyList)
            ClosePanel(UiNames.GuildFirstCreate)
            local guildInfo = ModuleCenter.Guild:GetGuildInfo()
            if guildInfo then
                ShowSysMsg(string.replace(I18nText(5586),guildInfo.name))
            end
            CtrlCenter.Guild:OpenGuild()
            FireEvent(EventNames.GUILD_JOIN)
        end
        return
    end
    for k, guildId in ipairs(pb.guildIds) do
        ModuleCenter.Guild:SetGuildApplyState(guildId, true)
    end
    FireEvent(EventNames.GUILD_LIST_CHANGE)
end

-- 创建军团
function LxGuildHandler:OnCreateGuildResp(pb)
    ModuleCenter.Guild:SetGuildInfo(pb.globalObj.guildObj)
