    ModuleCenter.Guild:SetGuildPermissions(pb.globalObj.permissions)
    ModuleCenter.Guild:SetGuildRankConditions(pb.globalObj.conditions)
    ModuleCenter.Guild:SetGuildOpenRankState(pb.globalObj.openRank)
    ClosePanel(UiNames.GuildCreate)
    ClosePanel(UiNames.GuildApplyList)
    ClosePanel(UiNames.GuildFirstCreate)
    CtrlCenter.Guild:OpenGuild()
    CtrlCenter.City:RefreshBuildGuildHelp()
    FireEvent(EventNames.GUILD_INFO_CHANGE)
    FireEvent(EventNames.GUILD_HELPRED)
    FireEvent(EventNames.GUILD_JOIN)
end

