-- 查看军团申请列表
function LxGuildHandler:OnViewApplyListResp(pb)
    local oldMap = ModuleCenter.Guild:GetGuildPlayerApplyMap()
    local newMap = {}
    local curTime = GetTimestamp()
    local roleId
    local change = false
    for _, v in ipairs(pb.roleList) do
        roleId = v.roleId
        if oldMap[roleId] then
            newMap[roleId] = oldMap[roleId]
        else
            change = true
            newMap[roleId] = curTime
        end
    end
    ModuleCenter.Guild:SetGuildPlayerApplyMap(newMap)
    ModuleCenter.Guild:SetGuildPlayerApplyList(pb.roleList)
    ModuleCenter.Guild:SetGuildUpgradeRequestList(pb.requires)
    FireEvent(EventNames.GUILD_PLAYER_APPLY_LIST_RETURN)

    if change then
        FireEvent(EventNames.GUILD_PLAYER_APPLY_RED_CHANGE)
    end
end

