function LxGuildHandler:OnGuildInviteRejectResp(pb)
    if pb.type == 0 then --同意加入同盟
        if CtrlCenter.Guild:HadGuild() then
            if IsOpenPanel(UiNames.GuildInvitationList) then
                ClosePanel(UiNames.GuildInvitationList)
            end
            CtrlCenter.Guild:OpenGuild()
        end
    end
end

