-- 请求援助
function LxGuildHandler:OnGuildAskHelpResp(pb)
    local moreInfo = pb.moreInfo
    if moreInfo ~= "" then
        local helpInfo = string.split(moreInfo, "_")
        local info1 = checknumber(helpInfo[1])
        local info2 = checknumber(helpInfo[2])
        ModuleCenter.Building:SetBuildingHelpState(info1)
        CtrlCenter.City:RefreshBuildGuildHelp()
        if pb.rewardInfo then
            pb.rewardInfo.windowType = 1
            FireEvent(EventNames.REWARDS_RECEIVED, RewardRecvType.GuildAidReward, pb.rewardInfo)
        end
    end
    if pb.guildCoin > 0 then
        ModuleCenter.Guild:SetGuildCoinNum(pb.guildCoin)
    end
    FireEvent(EventNames.GUILD_COIN_RETURN)

end

-- 帮助其他成员
function LxGuildHandler:OnGuildHelpMemberResp(pb)
    if pb.helpId == 0 then
        ShowSysMsg(I18nText(8334))
        self:GuildHelpListReq()
    end
    if pb.rewardInfo then
        pb.rewardInfo.windowType = 1
        FireEvent(EventNames.REWARDS_RECEIVED, RewardRecvType.GuildHelpReward, pb.rewardInfo)
    end
    if pb.guildCoin > 0 then
        ModuleCenter.Guild:SetGuildCoinNum(pb.guildCoin)
    end
    FireEvent(EventNames.GUILD_COIN_RETURN)
end

