-- 帮助信息更新通知,如果停留在帮助页面,刷新信息
function LxGuildHandler:OnGuildHelpUpdateResp(pb)
    -- 1-刷新帮助信息,2-清空帮助信息
    if pb.updateType == 1 or pb.updateType == 2 then
        self:GuildHelpListReq()
    end
    if pb.guildCoin > 0 and pb.maxGuildCoin > 0 then
        ModuleCenter.Guild:SetGuildCoinNum(pb.guildCoin,pb.maxGuildCoin)
    end
    FireEvent(EventNames.GUILD_COIN_RETURN)
end

